// Page Query Engine (Normalize Bing GetPageStats output)
// Output: 1 item => { meta, rows[] }

function bingDateToISO(bingDateStr) {
  const m = String(bingDateStr).match(/\/Date\((\d+)([+-]\d{4})?\)\//);
  if (!m) return null;
  const ms = Number(m[1]);
  return new Date(ms).toISOString().slice(0, 10);
}
function num(x){ return x === null || x === undefined || x === '' ? 0 : Number(x); }

const root = $input.first().json;

// robust read: sometimes root is {d:[...]} or [{d:[...]}]
const raw = Array.isArray(root?.d) ? root.d
        : Array.isArray(root?.[0]?.d) ? root[0].d
        : [];

const rows = raw.map(r => ({
  page: r.Url || r.URL || r.Page || r.page || r.url || null,
  date: r.Date ? bingDateToISO(r.Date) : null,
  clicks: num(r.Clicks),
  impressions: num(r.Impressions),
  avgImprPos: (r.AvgImpressionPosition === -1 ? null : (r.AvgImpressionPosition ?? null)),
