}));

return [{
  json: {
    meta: { source: "Bing GetPageStats", generated_at: new Date().toISOString() },
    rows
  }
}];

// ENGINE — Query Stats + AI Signals
// Input: Bing GetQueryStats response (usually { d: [...] } or [{ d: [...] }])
// Output: one item with query_ranked_7d, query_ranked_28d, windows, debug, meta

function bingDateToISO(bingDateStr) {
  const m = String(bingDateStr).match(/\/Date\((\d+)([+-]\d{4})?\)\//);
  if (!m) return null;
  const ms = Number(m[1]);
  return new Date(ms).toISOString().slice(0, 10);
}

function num(x){ return x === null || x === undefined || x === '' ? 0 : Number(x); }
function clamp(n,a=0,b=100){ return Math.max(a, Math.min(b, n)); }
function safeDiv(a,b){ return b ? a/b : 0; }

function windowSplitCalendar(rows, windowDays) {
  const now = new Date();
  const end = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate())); // today 00:00Z

  const startA = new Date(end); startA.setUTCDate(startA.getUTCDate() - windowDays);
  const startB = new Date(end); startB.setUTCDate(startB.getUTCDate() - windowDays * 2);
  const endB   = new Date(end); endB.setUTCDate(endB.getUTCDate() - windowDays);

  const inRange = (d, s, e) => {
    if (!d) return false;
    const dt = new Date(d + "T00:00:00Z");
    return dt >= s && dt < e;
  };

  return {
    A: rows.filter(r => inRange(r.date, startA, end)),
    B: rows.filter(r => inRange(r.date, startB, endB)),
    window: {
      A: { start: startA.toISOString().slice(0,10), end: end.toISOString().slice(0,10) },
      B: { start: startB.toISOString().slice(0,10), end: endB.toISOString().slice(0,10) },
    }
  };
}

function groupByQuery(rows) {
  const m = new Map();
  for (const r of rows) {
    const q = r.query;
    if (!q) continue;

    const cur = m.get(q) || {
      key: q,
      clicks: 0,
      impressions: 0,
      avgImprPos_sum: 0,
      avgImprPos_cnt: 0
    };

    cur.clicks += r.clicks;
    cur.impressions += r.impressions;

    if (r.avgImprPos !== null && r.avgImprPos !== undefined && r.avgImprPos >= 0) {
      cur.avgImprPos_sum += r.avgImprPos;
      cur.avgImprPos_cnt += 1;
    }

    m.set(q, cur);
  }

  return [...m.values()].map(x => ({
    key: x.key,
    clicks: x.clicks,
    impressions: x.impressions,
    ctr: x.impressions ? x.clicks / x.impressions : 0,
    avgImprPos: x.avgImprPos_cnt ? (x.avgImprPos_sum / x.avgImprPos_cnt) : null
  }));
}

function indexByKey(arr){
  const m = new Map();
  for (const x of arr) m.set(x.key, x);
  return m;
}

// GEO-style score (kept)
function scoreItem(cur, prev){
  const imprA = cur?.impressions || 0;
  const clickA = cur?.clicks || 0;
  const ctrA = cur?.ctr ?? safeDiv(clickA, imprA);

  const imprB = prev?.impressions || 0;
  const clickB = prev?.clicks || 0;

  const imprGrowth = imprB ? (imprA - imprB) / imprB : (imprA > 0 ? 1 : 0);
  const clickGrowth = clickB ? (clickA - clickB) / clickB : (clickA > 0 ? 1 : 0);

  const gImpr = clamp((imprGrowth + 1) * 50) / 100;
  const gClick = clamp((clickGrowth + 1) * 50) / 100;

  const lowCtrBonus =
    (imprA >= 30 && ctrA <= 0.01) ? 1 :
    (imprA >= 50 && ctrA <= 0.02) ? 0.7 :
    (imprA >= 100 && ctrA <= 0.03) ? 0.5 : 0;

  const newVis = (imprB === 0 && imprA >= 20) ? 1 : 0;

  const score = (gImpr * 55) + (gClick * 20) + (lowCtrBonus * 15) + (newVis * 10);

  return {
    clicks_a: clickA, impressions_a: imprA, ctr_a: ctrA,
    clicks_b: clickB, impressions_b: imprB,
    impr_growth: imprGrowth, click_growth: clickGrowth,
    score: clamp(Math.round(score)),
    signals: {
      rising_visibility: imprGrowth > 0.2,
      low_ctr_ai_intent: lowCtrBonus > 0,
      new_visibility: newVis === 1,
    }
  };
}

// AI citation signal (lightweight, safe even with small data)
function aiCitationScore(queryKey, cur, prev){
  const imprA = cur?.impressions || 0;
  const ctrA  = cur?.ctr ?? safeDiv(cur?.clicks || 0, imprA);
  const avgPos = cur?.avgImprPos;

  // Position score
  let posScore = 0.35;
  if (avgPos !== null && avgPos !== undefined) {
    if (avgPos <= 3) posScore = 1.0;
    else if (avgPos <= 6) posScore = 0.75;
    else if (avgPos <= 10) posScore = 0.45;
    else posScore = 0.2;
  }

  // Low CTR score (early-stage friendly)
  let lowCtrScore = 0.2;
  if (imprA >= 10 && ctrA <= 0.05) lowCtrScore = 0.7;
  if (imprA >= 30 && ctrA <= 0.03) lowCtrScore = 0.9;
  if (imprA >= 50 && ctrA <= 0.02) lowCtrScore = 1.0;

  // Volume score
  let volumeScore = 0.15;
  if (imprA >= 10) volumeScore = 0.35;
  if (imprA >= 30) volumeScore = 0.55;
  if (imprA >= 80) volumeScore = 0.75;
  if (imprA >= 200) volumeScore = 1.0;

  // Intent heuristic
  const q = String(queryKey || "").toLowerCase();
  const infoHints = ["how", "what", "why", "guide", "tutorial", "best", "vs", "compare", "review", "price", "meaning", "definition", "explain"];
  const navHints  = ["login", "homepage", "official", "site:", "facebook", "instagram", "youtube", "anergyacademy"];

  const isInfo = infoHints.some(h => q.includes(h));
  const isNav  = navHints.some(h => q.includes(h));

  let intentScore = 0.5;
  if (isInfo) intentScore = 0.85;
  if (isNav) intentScore = 0.25;

  const score =
    (posScore * 40) +
    (lowCtrScore * 30) +
    (volumeScore * 20) +
    (intentScore * 10);

  const aiScore = clamp(Math.round(score));

  const tier =
    aiScore >= 75 ? "HIGH" :
    aiScore >= 55 ? "MEDIUM" :
    "LOW";

  return {
    ai_citation_score: aiScore,
    ai_citation_tier: tier
  };
}

// ---- Read input safely ----
const first = $input.first().json;

// Bing sometimes returns [{ d: [...] }] or { d: [...] }
const root = Array.isArray(first) ? first[0] : first;
const rawRows = Array.isArray(root?.d) ? root.d : (Array.isArray(first?.d) ? first.d : []);

// Normalize rows
const rows = rawRows.map(r => ({
  query: r.Query,
  date: bingDateToISO(r.Date),
  clicks: num(r.Clicks),
  impressions: num(r.Impressions),
  avgImprPos: (r.AvgImpressionPosition === -1 ? null : num(r.AvgImpressionPosition)),
}));

// Split windows
const w7  = windowSplitCalendar(rows, 7);
const w28 = windowSplitCalendar(rows, 28);

// Aggregate per window
const A7  = groupByQuery(w7.A);
const B7  = groupByQuery(w7.B);
const A28 = groupByQuery(w28.A);
const B28 = groupByQuery(w28.B);

// Rank + attach AI signals
function rank(A, B){
  const idx = indexByKey(B);
  return A.map(a => {
      const prev = idx.get(a.key);
      const base = scoreItem(a, prev);
      const ai   = aiCitationScore(a.key, a, prev);
      return {
        key: a.key,
        ...base,
        avgImprPos: a.avgImprPos,
        ...ai,
      };
    })
    .sort((x,y) => (y.score - x.score));
}

return [{
  json: {
    meta: { source: "Bing GetQueryStats", generated_at: new Date().toISOString() },

    windows: {
      d7:  w7.window,
      d28: w28.window,
    },

    debug: {
      total_rows: rows.length,
      d7:  { A_rows: w7.A.length,  B_rows: w7.B.length },
      d28: { A_rows: w28.A.length, B_rows: w28.B.length },
    },

    query_ranked_7d: rank(A7, B7),
    query_ranked_28d: rank(A28, B28),
  }
}];

// Workflow B: Report Builder (English)
// Input: one item from Workflow A
// Output: two items: 7D report + 28D report

const engine = $input.first().json;

// Helpers
function n(x){ return x === null || x === undefined ? 0 : Number(x); }
function pct(x, digits=1){ return (n(x) * 100).toFixed(digits) + "%"; }
function top(arr, k=10){ return (arr || []).slice(0, k); }
function byScore(arr){ return (arr || []).slice().sort((a,b) => (b.score ?? 0) - (a.score ?? 0)); }

// Opportunity rules (tune later)
function isRising(x){ return !!x?.signals?.rising_visibility; }
function isNewVis(x){ return !!x?.signals?.new_visibility; }
function isLowCtrOpp(x){
  // early-stage friendly thresholds
  return n(x.impressions_a) >= 3 && n(x.ctr_a) <= 0.05;
}

function summarize(list){
  const clicks = list.reduce((s,x) => s + n(x.clicks_a), 0);
  const impr   = list.reduce((s,x) => s + n(x.impressions_a), 0);
  const ctr    = impr ? clicks / impr : 0;
  return { clicks, impressions: impr, ctr };
}

function buildReport(windowKey){
  const is7 = windowKey === "d7";
  const ranked = is7 ? (engine.query_ranked_7d || []) : (engine.query_ranked_28d || []);
  const win = engine?.windows?.[windowKey] || {};

  const rankedSorted = byScore(ranked);

  const top10 = top(rankedSorted, 10);

  const rising = rankedSorted.filter(isRising).slice(0, 15);
  const newVis = rankedSorted.filter(isNewVis).slice(0, 15);
  const lowCtr = rankedSorted.filter(isLowCtrOpp).slice(0, 15);

  const totals = summarize(rankedSorted);

  // Insights (plain English, copy-ready)
  const insights = [];
  if (top10.length) insights.push(`Top queries show where Bing is already testing your visibility in the last ${is7 ? "7 days" : "28 days"}.`);
  if (rising.length) insights.push(`Rising visibility queries indicate topics that are gaining traction and should be reinforced with better on-page answers.`);
  if (lowCtr.length) insights.push(`Low-CTR queries with impressions often indicate “answer intent” (people see you but don’t click). These are prime candidates for Q&A blocks and clearer titles.`);
  if (!rising.length && !lowCtr.length) insights.push(`Data volume is still small; use this report to monitor early index signals rather than making big content decisions yet.`);

  // Action plan (simple + useful)
  const actions = [
    `Create 1 short supporting post targeting the #1 rising query (or the top query if rising list is empty).`,
    `Add a 5–8 question FAQ block to the best-matching existing page for the top 3 queries.`,
    `Ensure internal links: link from your main pillar page to the pages/posts covering the top queries.`,
  ];

  return {
    meta: engine.meta || {},
    report_type: is7 ? "BING_QUERY_REPORT_7D" : "BING_QUERY_REPORT_28D",
    window: win, // A/B date ranges
    totals,
    sections: {
      top_queries: top10.map(x => ({
        query: x.key,
        clicks: x.clicks_a,
        impressions: x.impressions_a,
        ctr: pct(x.ctr_a),
        avg_impr_position: x.avgImprPos,
        score: x.score,
        signals: x.signals
      })),
      rising_visibility: rising.map(x => ({
        query: x.key,
        impressions: x.impressions_a,
        ctr: pct(x.ctr_a),
        avg_impr_position: x.avgImprPos,
        score: x.score
      })),
      low_ctr_opportunities: lowCtr.map(x => ({
        query: x.key,
        impressions: x.impressions_a,
        ctr: pct(x.ctr_a),
        avg_impr_position: x.avgImprPos,
        recommended_fix: "Improve title/H1 alignment + add FAQ/Q&A block + strengthen internal links"
      })),
      new_visibility: newVis.map(x => ({
        query: x.key,
        impressions: x.impressions_a,
        avg_impr_position: x.avgImprPos,
        note: "New query detected in this window"
      }))
    },
    insights,
    actions
  };
}

// Build two separate reports
const report7  = buildReport("d7");
const report28 = buildReport("d28");

// Return as two separate n8n items
return [
  { json: report7 },
  { json: report28 }
];

