function buildReport(rows, windowDays){
  // if Date is missing, everything collapses to today => useless windows
  // So we drop rows without date to avoid fake signals
  const dated = rows.filter(r => !!r.date);

  const w = windowSplitCalendar(dated, windowDays);
  const A = groupByPage(w.A);
  const B = groupByPage(w.B);

  const idxB = indexByKey(B);

  const ranked = A.map(a => {
    const prev = idxB.get(a.key);
    const base = scoreItem(a, prev);
    return {
      page_url: a.key,
      clicks: base.clicks_a,
      impressions: base.impressions_a,
      ctr: pct(base.ctr_a),
      avg_impr_position: a.avgImprPos,
      score: base.score,
      signals: base.signals
    };
  }).sort((x,y) => y.score - x.score);

  const totalClicks = A.reduce((s,x)=>s+(x.clicks||0),0);
  const totalImpr   = A.reduce((s,x)=>s+(x.impressions||0),0);
  const totalCtr    = safeDiv(totalClicks, totalImpr);

  const top_pages = ranked.slice(0, 15);

  const rising_visibility = ranked.filter(x => x.signals?.rising_visibility).slice(0, 15);

  const low_ctr_opportunities = ranked
    .filter(x => {
      const ctrN = Number(String(x.ctr).replace('%','')) / 100;
      return x.impressions >= 10 && ctrN <= 0.02;
    })
    .slice(0, 15)
    .map(x => ({
      page_url: x.page_url,
      impressions: x.impressions,
      ctr: x.ctr,
      avg_impr_position: x.avg_impr_position,
      recommended_fix: "Improve title/H1 alignment + add FAQ/Q&A block + strengthen internal links"
    }));

  const new_visibility = ranked.filter(x => x.signals?.new_visibility).slice(0, 15);

  const insights = [
    `Top pages show where Bing is testing your visibility in the last ${windowDays} days.`,
    "Rising visibility pages indicate content that should be reinforced with better on-page answers.",
    "Low-CTR pages with impressions often indicate mismatch between snippet/title and intent. These are prime candidates for title fixes + FAQ blocks."
  ];

  const actions = [
    "Update the top 1–2 pages with rising visibility: add a 5–8 question FAQ block and tighten the first 120 words to match intent.",
    "Add 3–5 internal links from your pillar page to the top pages in this report (contextual anchors, not generic).",
    "For low-CTR pages: rewrite title + meta description to include the exact query language and a clearer benefit."
  ];

  return {
    report_type: windowDays === 7 ? "BING_PAGE_REPORT_7D" : "BING_PAGE_REPORT_28D",
    window: w.window,
    totals: { clicks: totalClicks, impressions: totalImpr, ctr: totalCtr },
    sections: { top_pages, rising_visibility, low_ctr_opportunities, new_visibility },
    insights,
    actions,
    debug: { total_rows: dated.length, A_rows: w.A.length, B_rows: w.B.length }
  };
}

