// Get all 4 items (Query 7d/28d, Page 7d/28d)
const items = $input.all();

// Helper to find specific report types in the list
const findReport = (type) => items.find(i => i.json.report_type === type)?.json || null;

// Create the Master JSON
const masterReport = {
