// 1. Get input data
const input = $input.first().json;
// Safety check: ensure arrays exist even if empty
const q7 = input.bing_data?.query_7d?.sections?.top_queries || [];
const q28 = input.bing_data?.query_28d?.sections?.top_queries || [];
const p7 = input.bing_data?.page_7d?.sections?.top_pages || [];

// Helper to find 28-day data
const find28 = (queryText) => q28.find(i => i.query === queryText) || {};

const reportData = {
  meta: { generated_at: new Date().toISOString(), mode: "Baby Site Mode (All Data)" },
  geo_opportunities: [], 
  commercial_wins: [],   
  early_signals: [],     // NEW: For keywords with just 1-2 impressions
  urgent_fixes: []       
};

// 3. Loop through ALL 7-day data
for (const item of q7) {
  const query = item.query;
  const impr7 = Number(item.impressions) || 0;
  const clicks7 = Number(item.clicks) || 0;
  const pos7 = Number(item.avg_impr_position) || 0;

  // Get 28-day comparison
  const item28 = find28(query);
  const impr28 = Number(item28.impressions) || 0;
  const baselineWeekly = impr28 > 0 ? (impr28 / 4) : 0;

  // --- LOGIC UPDATES FOR NEW SITES ---

  // 1. Commercial Logic (Keep this)
  const buyKeywords = ["buy", "course", "service", "price", "review", "audit", "training", "bazaar", "amazon", "guide", "how"];
  const isCommercial = buyKeywords.some(k => query.toLowerCase().includes(k));

  // 2. GEO Opportunity (Relaxed: Any position, Any impression, 0 Clicks)
  // If you are ranking #50 but got an impression, it counts!
  const isGeoOpp = impr7 > 0 && clicks7 === 0;

  // 3. Trending (Relaxed: Any growth counts)
  const isTrending = impr7 > baselineWeekly;

  // --- CATEGORIZATION ---

  // A. "Cite Me" Candidates (GEO)
  if (isGeoOpp) {
    reportData.geo_opportunities.push({
      query: query,
      position: Math.round(pos7 * 10) / 10,
      impressions_7d: impr7,
      insight: `Rank #${Math.round(pos7)} - Zero clicks (Potential AI Answer)`
    });
  }

  // B. Commercial / Intent Wins
  if (isCommercial) {
    reportData.commercial_wins.push({
      query: query,
      trend: isTrending ? "UP 📈" : "Stable",
      stats: `${impr7} impr`,
      matched_url: "Check Bing Master"
    });
  }

  // C. Early Signals (Everything else!)
  // If it didn't fit above, put it here so you see EVERYTHING.
  if (!isGeoOpp && !isCommercial) {
    reportData.early_signals.push({
      query: query,
      stats: `${impr7} impr (Pos ${Math.round(pos7)})`
    });
  }
}

// Debug: If still empty, force a message
if (q7.length === 0) {
  reportData.debug_note = "CRITICAL: No data found in Input. Please check if Bing Webmaster has data for these dates.";
}

return [{ json: reportData }];
